const body = $input.first().json;

return {
  message: body.message || body.text || "",
  phone: body.phone || body.from || "",
  name: body.name || "Cliente"
};

const response = $input.first().json;
const token = '';
const phone = response.phone;
const reply = response.reply || "Procesando tu consulta...";

const result = await this.helpers.request({
  method: 'POST',
  uri: 'https://graph.facebook.com/v22.0/1022623927610993/messages',
  headers: {
    'Authorization': 'Bearer ' + token,
    'Content-Type': 'application/json'
  },
  body: {
    messaging_product: 'whatsapp',
    to: phone,
    type: 'text',
    text: { preview_url: false, body: reply }
  },
  json: true
});

return { sent: true, phone, reply };
